import fs from "node:fs/promises";
import path from "node:path";
import { pathToFileURL } from "node:url";

const repoRoot = path.resolve(import.meta.dirname, "..");
const dataFiles = [
  "exercise-data.js",
  "solution-code.js",
  "test-data/tests-py01-03.js",
  "test-data/tests-py04-07.js",
  "test-data/tests-py08-11.js",
];

globalThis.window = {};
for (const file of dataFiles) {
  await import(pathToFileURL(path.join(repoRoot, file)));
}

const course = globalThis.window.COURSE_DATA;
const solutions = globalThis.window.SOLUTION_CODE;
const specs = globalThis.window.EXERCISE_TESTS;
const starters = {};

for (const chapter of course.chapters) {
  for (const exercise of chapter.exercises) {
    const id = String(exercise.id);
    const spec = specs[id];

    if (spec.mode === "script") {
      starters[id] = [
        "# Write your program below.",
        "# Read the contract and visible examples before you begin.",
        "",
      ].join("\n");
      continue;
    }

    const source = solutions[id] || "";
    const calls = spec.tests.map((test) => test.call || "").join("\n");
    const signatures = [...source.matchAll(/^def\s+([A-Za-z_]\w*)\s*\(([^\n]*)\)\s*:/gm)]
      .filter((match) => new RegExp(`\\b${match[1]}\\s*\\(`).test(calls))
      .map((match) => match[0]);

    if (signatures.length === 0) {
      throw new Error(`${id}: could not find a tested public function signature.`);
    }

    starters[id] = [
      "# Keep these public function names and parameters so the tests can call your code.",
      ...signatures.flatMap((signature, index) => [
        ...(index === 0 ? [] : [""]),
        signature,
        "    # TODO: replace pass with your implementation.",
        "    pass",
      ]),
      "",
    ].join("\n");
  }
}

const output = [
  "// Generated by scripts/build-starter-bundle.mjs. Do not edit by hand.",
  "// This bundle contains public signatures only; repository solutions stay private.",
  `window.STARTER_CODE = ${JSON.stringify(starters, null, 2)};`,
  "",
].join("\n");

await fs.writeFile(path.join(repoRoot, "starter-code.js"), output, "utf8");
console.log(`Generated safe starter code for ${Object.keys(starters).length} exercises.`);
